    24	    @VisibleForTesting
    25	    static List<QueryFilter> getQueryFilters(Map<String, List<String>> queryParams) {
    26	        List<QueryFilter> filters = new ArrayList<>();
    27	        Map<QueryFilter.Op, Map<String, String>> labelsByOperation = new HashMap<>(); // Group labels by operation
    28	
    29	        for (Map.Entry<String, List<String>> entry : queryParams.entrySet()) {
    30	            String key = entry.getKey();
    31	            if (!key.startsWith("filters[")) {
    32	                continue;
    33	            }
    34	
    35	            Matcher matcher = FILTER_PATTERN.matcher(key);
    36	
    37	            if (matcher.matches()) {
    38	                parseFilters(entry.getValue(), matcher, filters, labelsByOperation);
    39	            }
    40	        }
    41	        // Add a QueryFilter for each operation's labels
    42	        labelsByOperation.forEach((operation, labels) ->
    43	        {
    44	            if (!labels.isEmpty()) {
    45	                filters.add(
    46	                    QueryFilter.builder()
    47	                        .field(QueryFilter.Field.LABELS)
    48	                        .operation(operation)
    49	                        .value(labels)
    50	                        .build()
    51	                );
    52	            }
    53	        });
    54	
    55	        return filters;
    56	    }
