    71	    private static void parseFilters(List<String> values, Matcher matcher, List<QueryFilter> filters, Map<QueryFilter.Op, Map<String, String>> labelsByOperation) {
    72	        String fieldStr = matcher.group(1);
    73	        String operationStr = matcher.group(2);
    74	        String nestedKey = matcher.group(3); // Extract nested key if present
    75	
    76	        QueryFilter.Field field = QueryFilter.Field.fromString(fieldStr);
    77	        QueryFilter.Op operation = QueryFilter.Op.valueOf(operationStr);
    78	
    79	        // For labels: Add the key-value to the appropriate operation's map
    80	        if (field == QueryFilter.Field.LABELS && nestedKey != null) {
    81	            labelsByOperation.computeIfAbsent(operation, k -> new HashMap<>()).put(nestedKey, values.getFirst());
    82	        } else {
    83	            List<Object> parsedValues = nestedKey != null ? List.of(Map.of(nestedKey, values.getFirst())) : parseValues(values, field, operation);
    84	            filters.addAll(
    85	                parsedValues.stream().map(
    86	                    parsedValue -> QueryFilter.builder()
    87	                        .field(field)
    88	                        .operation(operation)
    89	                        .value(parsedValue)
    90	                        .build()
    91	                ).toList()
    92	            );
    93	        }
