private Condition applyScopeCondition(Object value, QueryFilter.Op operation) {
    List<FlowScope> flowScopes = Enums.fromList(value, FlowScope.class);
    if (flowScopes.size() > 1) {
        throw new InvalidQueryFiltersException("Only one scope can be use in the same time");
    }
    FlowScope scope = flowScopes.getFirst();

    String systemNamespace = this.kestraConfig.getSystemFlowNamespace();
    return switch (operation) {
        case EQUALS -> FlowScope.USER.equals(scope) ? field("namespace").ne(systemNamespace) : field("namespace").eq(systemNamespace);
        case NOT_EQUALS -> FlowScope.USER.equals(scope) ? field("namespace").eq(systemNamespace) : field("namespace").ne(systemNamespace);
        default -> throw new InvalidQueryFiltersException("Unsupported operation for SCOPE: " + operation);
    };
}

action.new_str:
private Condition applyScopeCondition(Object value, QueryFilter.Op operation) {
    EnumSet<FlowScope> flowScopes = flowScopes(value);
    return switch (operation) {
        case EQUALS -> scopeCondition(singleScope(flowScopes));
        case NOT_EQUALS -> scopeCondition(excludedScopes(flowScopes));
        case IN -> scopeCondition(flowScopes);
        case NOT_IN -> scopeCondition(excludedScopes(flowScopes));
        default -> throw new InvalidQueryFiltersException("Unsupported operation for SCOPE: " + operation);
    };
}

private EnumSet<FlowScope> flowScopes(Object value) {
    if (value instanceof String stringValue && stringValue.contains(",")) {
        EnumSet<FlowScope> flowScopes = EnumSet.noneOf(FlowScope.class);
        Arrays.stream(stringValue.split(","))
            .map(String::trim)
            .filter(scope -> !scope.isEmpty())
            .map(scope -> FlowScope.valueOf(scope.toUpperCase()))
            .forEach(flowScopes::add);
        return flowScopes;
    }

    EnumSet<FlowScope> flowScopes = EnumSet.noneOf(FlowScope.class);
    flowScopes.addAll(Enums.fromList(value, FlowScope.class));
    return flowScopes;
}

private FlowScope singleScope(EnumSet<FlowScope> flowScopes) {
    if (flowScopes.size() != 1) {
        throw new InvalidQueryFiltersException("Only one scope can be used at the same time");
    }
    return flowScopes.iterator().next();
}

private EnumSet<FlowScope> excludedScopes(EnumSet<FlowScope> flowScopes) {
    EnumSet<FlowScope> scopes = EnumSet.allOf(FlowScope.class);
    scopes.removeAll(flowScopes);
    return scopes;
}

private Condition scopeCondition(FlowScope scope) {
    String systemNamespace = this.kestraConfig.getSystemFlowNamespace();
    return FlowScope.USER.equals(scope) ? field("namespace").ne(systemNamespace) : field("namespace").eq(systemNamespace);
}

private Condition scopeCondition(EnumSet<FlowScope> flowScopes) {
    if (flowScopes.isEmpty()) {
        return DSL.falseCondition();
    }
    if (flowScopes.containsAll(Arrays.asList(FlowScope.values()))) {
        return DSL.noCondition();
    }
    return scopeCondition(singleScope(flowScopes));
}

